import java.util.*;

public class HeapPatterns {

    // ── Top-K Largest Elements ──────────────────────────────────────────────
    // Min-heap of size K: if new element > heap.peek(), replace
    public static int[] topKLargest(int[] nums, int k) {
        PriorityQueue<Integer> minHeap = new PriorityQueue<>(); // min at top

        for (int num : nums) {
            minHeap.offer(num);
            if (minHeap.size() > k) minHeap.poll(); // remove smallest
        }
        return minHeap.stream().mapToInt(Integer::intValue).toArray();
    }

    // ── Kth Largest Element ─────────────────────────────────────────────────
    public static int findKthLargest(int[] nums, int k) {
        PriorityQueue<Integer> minHeap = new PriorityQueue<>();
        for (int num : nums) {
            minHeap.offer(num);
            if (minHeap.size() > k) minHeap.poll();
        }
        return minHeap.peek(); // root = kth largest
    }

    // ── Merge K Sorted Lists ────────────────────────────────────────────────
    public static int[] mergeKSorted(int[][] lists) {
        // Min-heap of [value, list-index, element-index]
        PriorityQueue<int[]> pq = new PriorityQueue<>(Comparator.comparingInt(a -> a[0]));
        int total = 0;
        for (int i = 0; i < lists.length; i++) {
            if (lists[i].length > 0) {
                pq.offer(new int[]{lists[i][0], i, 0});
                total += lists[i].length;
            }
        }
        int[] result = new int[total];
        int idx = 0;
        while (!pq.isEmpty()) {
            int[] curr = pq.poll();
            result[idx++] = curr[0];
            int li = curr[1], ei = curr[2];
            if (ei + 1 < lists[li].length)
                pq.offer(new int[]{lists[li][ei + 1], li, ei + 1});
        }
        return result;
    }

    // ── Running Median (Two-Heap Pattern) ──────────────────────────────────
    // maxHeap holds lower half, minHeap holds upper half
    static PriorityQueue<Integer> lower = new PriorityQueue<>(Collections.reverseOrder());
    static PriorityQueue<Integer> upper = new PriorityQueue<>();

    public static void addNum(int num) {
        lower.offer(num);
        upper.offer(lower.poll()); // balance: push max of lower to upper
        if (lower.size() < upper.size()) lower.offer(upper.poll()); // maintain lower >= upper size
    }

    public static double findMedian() {
        return lower.size() > upper.size()
            ? lower.peek()
            : (lower.peek() + upper.peek()) / 2.0;
    }
}

import java.util.*;

public class MonotonicStack {

    // ── Next Greater Element ────────────────────────────────────────────────
    public static int[] nextGreater(int[] arr) {
        int n = arr.length;
        int[] result = new int[n];
        Arrays.fill(result, -1); // default: no greater element
        Deque<Integer> stack = new ArrayDeque<>(); // stores indices

        for (int i = 0; i < n; i++) {
            while (!stack.isEmpty() && arr[stack.peek()] < arr[i]) {
                result[stack.pop()] = arr[i]; // arr[i] is NGE for stack top
            }
            stack.push(i);
        }
        return result;
    }

    // ── Daily Temperatures ──────────────────────────────────────────────────
    // How many days until a warmer temperature?
    public static int[] dailyTemperatures(int[] temps) {
        int n = temps.length;
        int[] answer = new int[n];
        Deque<Integer> stack = new ArrayDeque<>();

        for (int i = 0; i < n; i++) {
            while (!stack.isEmpty() && temps[stack.peek()] < temps[i]) {
                int j = stack.pop();
                answer[j] = i - j; // days until warmer
            }
            stack.push(i);
        }
        return answer;
    }

    // ── Largest Rectangle in Histogram ─────────────────────────────────────
    public static int largestRectangle(int[] heights) {
        int n = heights.length;
        Deque<Integer> stack = new ArrayDeque<>();
        int maxArea = 0;

        for (int i = 0; i <= n; i++) {
            int h = (i == n) ? 0 : heights[i]; // sentinel 0 flushes stack
            while (!stack.isEmpty() && heights[stack.peek()] > h) {
                int height = heights[stack.pop()];
                int width  = stack.isEmpty() ? i : i - stack.peek() - 1;
                maxArea = Math.max(maxArea, height * width);
            }
            stack.push(i);
        }
        return maxArea;
    }

    // ── Trapping Rain Water ─────────────────────────────────────────────────
    public static int trap(int[] height) {
        Deque<Integer> stack = new ArrayDeque<>();
        int water = 0;
        for (int i = 0; i < height.length; i++) {
            while (!stack.isEmpty() && height[stack.peek()] < height[i]) {
                int bottom = stack.pop();
                if (stack.isEmpty()) break;
                int width = i - stack.peek() - 1;
                int h     = Math.min(height[i], height[stack.peek()]) - height[bottom];
                water += width * h;
            }
            stack.push(i);
        }
        return water;
    }
}
